-- Migration: Add Star class assignments for 2026-04-20
-- Creates grade-targeted assignments for 8 students across Reading, Math, Writing, and SEL

-- Create user_grade_levels table if it doesn't exist
CREATE TABLE IF NOT EXISTS user_grade_levels (
  user_id TEXT PRIMARY KEY REFERENCES users(id),
  reading_grade INTEGER,
  math_grade INTEGER,
  writing_grade INTEGER
);

-- Insert student per-subject grades
ON CONFLICT (user_id) DO UPDATE SET
  reading_grade = EXCLUDED.reading_grade,
  math_grade = EXCLUDED.math_grade,
  writing_grade = EXCLUDED.writing_grade;

-- Delete any existing assignments for this date in Star class
DELETE FROM assignments
WHERE class_id = 'b0000000-0000-0000-0000-000000000002'
  AND scheduled_date = '2026-04-20';

