INSERT INTO assignments (id, class_id, teacher_id, title, description, content, target_subject, target_grade_min, target_grade_max, target_student_ids, scheduled_date, due_date, created_at) VALUES
  ('8e88c933-7f54-4960-a3c1-c51059156597', 'b0000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000002', '1st Grade Reading: Simple Words', 'Read simple sight words and match pictures.', '{"title":"Simple Words","subject":"Reading","grade":"1st Grade","instructions":"Look at each picture. Circle the correct word.","totalPoints":30,"sections":[{"title":"Match Words to Pictures","questions":[{"type":"multiple_choice","text":"Which word is the picture showing a cat?","options":["A. dog","B. cat","C. bird","D. fish"],"correctIndex":1,"points":6},{"type":"multiple_choice","text":"Which word matches this apple picture?","options":["A. orange","B. apple","C. banana","D. grape"],"correctIndex":1,"points":6},{"type":"multiple_choice","text":"Which word means the color red?","options":["A. blue","B. green","C. red","D. yellow"],"correctIndex":2,"points":6},{"type":"multiple_choice","text":"Which is a small animal?","options":["A. elephant","B. whale","C. ant","D. giraffe"],"correctIndex":2,"points":6},{"type":"short_answer","text":"Draw or write the word for a pet you like.","points":6}]}]}', 'reading', 1, 1, '["s0000000-0000-0000-0000-000000000007","s0000000-0000-0000-0000-000000000004"]', '2026-04-20', '2026-04-20 09:30:00', '2026-04-20T20:57:57.518Z'),
  ('37468b3e-f29f-420d-8795-ec3426992c78', 'b0000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000002', '2nd Grade Reading: CVC Words', 'Read and identify consonant-vowel-consonant words.', '{"title":"CVC Words","subject":"Reading","grade":"2nd Grade","instructions":"Read each word and answer the questions.","totalPoints":25,"sections":[{"title":"Consonant-Vowel-Consonant Words","questions":[{"type":"multiple_choice","text":"Which word is a CVC word?","options":["A. string","B. cat","C. straight","D. school"],"correctIndex":1,"points":5},{"type":"multiple_choice","text":"What is the vowel in the word \'dog\'?","options":["A. d","B. o","C. g","D. og"],"correctIndex":1,"points":5},{"type":"multiple_choice","text":"Which rhymes with \'hat\'?","options":["A. cat","B. hate","C. that","D. hot"],"correctIndex":0,"points":5},{"type":"short_answer","text":"Write a CVC word and draw it.","points":10}]}]}', 'reading', 2, 2, '["s0000000-0000-0000-0000-000000000006"]', '2026-04-20', '2026-04-20 09:30:00', '2026-04-20T20:57:57.519Z'),
  ('b77b8166-f1e9-4e50-afe1-186f4c9b9e9c', 'b0000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000002', '3rd Grade Reading: Short Stories', 'Read and comprehend short story passages.', '{"title":"Short Stories","subject":"Reading","grade":"3rd Grade","instructions":"Read the story and answer the questions below.","totalPoints":40,"sections":[{"title":"Story Comprehension","questions":[{"type":"multiple_choice","text":"What was the main character trying to do?","options":["A. find treasure","B. help a friend","C. solve a mystery","D. win a race"],"correctIndex":1,"points":10},{"type":"multiple_choice","text":"How did the character feel at the end?","options":["A. sad","B. happy","C. confused","D. angry"],"correctIndex":1,"points":10},{"type":"short_answer","text":"Why did the character make that choice?","points":10},{"type":"short_answer","text":"What would you do differently?","points":10}]}]}', 'reading', 3, 3, '["s0000000-0000-0000-0000-000000000005","s0000000-0000-0000-0000-000000000002","s0000000-0000-0000-0000-000000000003"]', '2026-04-20', '2026-04-20 09:30:00', '2026-04-20T20:57:57.519Z'),
  ('bf3bf4ec-dccf-4900-a953-3bef4bc294c5', 'b0000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000002', '5th Grade Reading: Complex Passage', 'Read and analyze a complex informational passage.', '{"title":"Complex Passage","subject":"Reading","grade":"5th Grade","instructions":"Read the passage carefully and answer all questions.","totalPoints":50,"sections":[{"title":"Reading Comprehension","questions":[{"type":"multiple_choice","text":"What is the main idea of the passage?","options":["A. animals adapt to environments","B. humans build cities","C. plants need water","D. weather changes daily"],"correctIndex":0,"points":10},{"type":"multiple_choice","text":"Which detail supports the main idea?","options":["A. polar bears have white fur","B. fish swim in water","C. birds fly in air","D. all of the above"],"correctIndex":3,"points":10},{"type":"short_answer","text":"Explain how one animal adapts to its environment.","points":15},{"type":"short_answer","text":"What would happen if that adaptation was removed?","points":15}]}]}', 'reading', 5, 5, '["s0000000-0000-0000-0000-000000000008","s0000000-0000-0000-0000-000000000001"]', '2026-04-20', '2026-04-20 09:30:00', '2026-04-20T20:57:57.519Z');
INSERT INTO assignments (id, class_id, teacher_id, title, description, content, target_subject, target_grade_min, target_grade_max, target_student_ids, scheduled_date, due_date, created_at) VALUES
  ('24a9ada0-fb20-4e3d-b140-eef2d958bde9', 'b0000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000002', '1st Grade Math: Counting', 'Count objects and solve simple addition.', '{"title":"Counting","subject":"Math","grade":"1st Grade","instructions":"Count the objects and write the number.","totalPoints":20,"sections":[{"title":"Counting and Addition","questions":[{"type":"fill_blank","text":"3 + 2 = ___","correctAnswer":"5","points":4},{"type":"fill_blank","text":"1 + 4 = ___","correctAnswer":"5","points":4},{"type":"fill_blank","text":"2 + 3 = ___","correctAnswer":"5","points":4},{"type":"fill_blank","text":"4 + 1 = ___","correctAnswer":"5","points":4},{"type":"short_answer","text":"Draw 3 circles and 2 squares. How many shapes total?","points":4}]}]}', 'math', 1, 1, '["s0000000-0000-0000-0000-000000000007"]', '2026-04-20', '2026-04-20 11:00:00', '2026-04-20T20:57:57.519Z'),
  ('df960a2d-71fc-42cd-8b2d-6f1a8e04036f', 'b0000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000002', '2nd Grade Math: Add and Subtract', 'Practice addition and subtraction to 20.', '{"title":"Add and Subtract","subject":"Math","grade":"2nd Grade","instructions":"Solve each problem.","totalPoints":30,"sections":[{"title":"Addition and Subtraction","questions":[{"type":"fill_blank","text":"7 + 5 = ___","correctAnswer":"12","points":6},{"type":"fill_blank","text":"15 - 3 = ___","correctAnswer":"12","points":6},{"type":"fill_blank","text":"8 + 6 = ___","correctAnswer":"14","points":6},{"type":"fill_blank","text":"18 - 4 = ___","correctAnswer":"14","points":6},{"type":"short_answer","text":"If you have 9 apples and eat 2, how many are left?","points":6}]}]}', 'math', 2, 2, '["s0000000-0000-0000-0000-000000000005","s0000000-0000-0000-0000-000000000006","s0000000-0000-0000-0000-000000000004"]', '2026-04-20', '2026-04-20 11:00:00', '2026-04-20T20:57:57.519Z'),
  ('7c870b01-757b-487a-9da4-649c94b98feb', 'b0000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000002', '3rd Grade Math: Multiplication Intro', 'Introduction to multiplication as repeated addition.', '{"title":"Multiplication Intro","subject":"Math","grade":"3rd Grade","instructions":"Solve each multiplication problem.","totalPoints":40,"sections":[{"title":"Multiplication","questions":[{"type":"fill_blank","text":"3 × 4 = ___","correctAnswer":"12","points":8},{"type":"fill_blank","text":"5 × 2 = ___","correctAnswer":"10","points":8},{"type":"fill_blank","text":"4 × 3 = ___","correctAnswer":"12","points":8},{"type":"short_answer","text":"Draw 3 groups of 4 stars. How many total?","points":8},{"type":"short_answer","text":"Explain multiplication using apples and baskets.","points":8}]}]}', 'math', 3, 3, '["s0000000-0000-0000-0000-000000000003"]', '2026-04-20', '2026-04-20 11:00:00', '2026-04-20T20:57:57.519Z'),
  ('141ba126-ec4d-46d1-aedb-21138da76329', 'b0000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000002', '4th Grade Math: Multi-Digit Multiplication', 'Multiply two-digit and three-digit numbers.', '{"title":"Multi-Digit Multiplication","subject":"Math","grade":"4th Grade","instructions":"Solve each multiplication problem.","totalPoints":40,"sections":[{"title":"Multi-Digit Multiplication","questions":[{"type":"fill_blank","text":"12 × 3 = ___","correctAnswer":"36","points":10},{"type":"fill_blank","text":"24 × 2 = ___","correctAnswer":"48","points":10},{"type":"fill_blank","text":"15 × 4 = ___","correctAnswer":"60","points":10},{"type":"short_answer","text":"Solve: 23 × 3 = ___","points":10}]}]}', 'math', 4, 4, '["s0000000-0000-0000-0000-000000000002"]', '2026-04-20', '2026-04-20 11:00:00', '2026-04-20T20:57:57.519Z'),
  ('f47502df-a5ae-4af2-a223-fd4b079f75b1', 'b0000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000002', '5th Grade Math: Decimals & Fractions', 'Work with decimals and fractions.', '{"title":"Decimals & Fractions","subject":"Math","grade":"5th Grade","instructions":"Solve each problem with decimals and fractions.","totalPoints":50,"sections":[{"title":"Decimals and Fractions","questions":[{"type":"fill_blank","text":"0.5 + 0.3 = ___","correctAnswer":"0.8","points":10},{"type":"fill_blank","text":"1/2 + 1/4 = ___","correctAnswer":"3/4","points":10},{"type":"fill_blank","text":"0.75 = ___/4","correctAnswer":"3","points":10},{"type":"short_answer","text":"Convert 0.25 to a fraction.","points":10},{"type":"short_answer","text":"Explain how decimals and fractions are related.","points":10}]}]}', 'math', 5, 5, '["s0000000-0000-0000-0000-000000000008","s0000000-0000-0000-0000-000000000001"]', '2026-04-20', '2026-04-20 11:00:00', '2026-04-20T20:57:57.519Z');
INSERT INTO assignments (id, class_id, teacher_id, title, description, content, target_subject, target_grade_min, target_grade_max, target_student_ids, scheduled_date, due_date, created_at) VALUES
  ('71bc1268-273f-47f2-8a7d-d739f1a9774a', 'b0000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000002', 'Kindergarten Writing: Trace and Copy', 'Trace letters and simple words.', '{"title":"Trace and Copy","subject":"Writing","grade":"K","instructions":"Trace the letters and simple words on the lines.","totalPoints":20,"sections":[{"title":"Tracing and Copying","questions":[{"type":"short_answer","text":"Trace the letter A five times.","points":4},{"type":"short_answer","text":"Copy the word CAT.","points":4},{"type":"short_answer","text":"Copy the word DOG.","points":4},{"type":"short_answer","text":"Write your name.","points":4},{"type":"short_answer","text":"Draw a picture of something you like.","points":4}]}]}', 'writing', 0, 0, '["s0000000-0000-0000-0000-000000000007"]', '2026-04-20', '2026-04-20 13:30:00', '2026-04-20T20:57:57.519Z'),
  ('dff247cd-90ad-4b17-bfc0-36378f1ea660', 'b0000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000002', '2nd Grade Writing: Sentence Writing', 'Write simple sentences with correct punctuation.', '{"title":"Sentence Writing","subject":"Writing","grade":"2nd Grade","instructions":"Write complete sentences with capital letters and periods.","totalPoints":25,"sections":[{"title":"Writing Sentences","questions":[{"type":"short_answer","text":"Write a sentence about your favorite animal.","points":5},{"type":"short_answer","text":"Write a sentence about something you did today.","points":5},{"type":"short_answer","text":"Write a question about a topic you like.","points":5},{"type":"short_answer","text":"Write a sentence using the word \'because\'.","points":5},{"type":"short_answer","text":"Write a sentence about your family.","points":5}]}]}', 'writing', 2, 2, '["s0000000-0000-0000-0000-000000000006","s0000000-0000-0000-0000-000000000004"]', '2026-04-20', '2026-04-20 13:30:00', '2026-04-20T20:57:57.519Z'),
  ('7d0c6371-39b0-49d0-8a81-db746dd67b33', 'b0000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000002', '3rd Grade Writing: Narrative Paragraph', 'Write a narrative paragraph with beginning, middle, and end.', '{"title":"Narrative Paragraph","subject":"Writing","grade":"3rd Grade","instructions":"Write a paragraph about something that happened to you.","totalPoints":40,"sections":[{"title":"Narrative Writing","questions":[{"type":"short_answer","text":"Describe what happened (the event).","points":10},{"type":"short_answer","text":"Explain why it was important or interesting.","points":10},{"type":"short_answer","text":"Describe how you felt about it.","points":10},{"type":"short_answer","text":"Write the whole paragraph together.","points":10}]}]}', 'writing', 3, 3, '["s0000000-0000-0000-0000-000000000005","s0000000-0000-0000-0000-000000000003"]', '2026-04-20', '2026-04-20 13:30:00', '2026-04-20T20:57:57.519Z'),
  ('c6154b57-b71e-4316-b54c-395c2d7c4c89', 'b0000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000002', '5th Grade Writing: Opinion Essay', 'Write a persuasive essay supporting your opinion.', '{"title":"Opinion Essay","subject":"Writing","grade":"5th Grade","instructions":"Write an essay supporting your opinion with facts and details.","totalPoints":50,"sections":[{"title":"Opinion Writing","questions":[{"type":"short_answer","text":"State your opinion clearly.","points":10},{"type":"short_answer","text":"Give three reasons that support your opinion.","points":15},{"type":"short_answer","text":"Provide examples or facts for each reason.","points":15},{"type":"short_answer","text":"Write your conclusion restating your opinion.","points":10}]}]}', 'writing', 5, 5, '["s0000000-0000-0000-0000-000000000008","s0000000-0000-0000-0000-000000000002","s0000000-0000-0000-0000-000000000001"]', '2026-04-20', '2026-04-20 13:30:00', '2026-04-20T20:57:57.519Z');
INSERT INTO assignments (id, class_id, teacher_id, title, description, content, target_subject, target_grade_min, target_grade_max, target_student_ids, scheduled_date, due_date, created_at) VALUES
  ('bf3b725d-9574-4fce-b37a-231145a7b5ac', 'b0000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000002', 'Growth Mindset: Learning from Challenges', 'Watch a video about growth mindset and reflect on learning.', '{"title":"Growth Mindset","subject":"SEL","grade":"All","instructions":"Watch the video and answer the reflection questions.","totalPoints":20,"sections":[{"title":"Growth Mindset Video","questions":[{"type":"short_answer","text":"What is the difference between a fixed mindset and a growth mindset?","points":5},{"type":"short_answer","text":"Describe a challenge you faced and how you overcame it.","points":5},{"type":"short_answer","text":"How can you use a growth mindset in school?","points":5},{"type":"short_answer","text":"What is one thing you want to improve this week?","points":5}]}]}', 'sel', 1, 5, '["s0000000-0000-0000-0000-000000000007","s0000000-0000-0000-0000-000000000008","s0000000-0000-0000-0000-000000000005","s0000000-0000-0000-0000-000000000002","s0000000-0000-0000-0000-000000000006","s0000000-0000-0000-0000-000000000003","s0000000-0000-0000-0000-000000000001","s0000000-0000-0000-0000-000000000004"]', '2026-04-20', '2026-04-20 14:30:00', '2026-04-20T20:57:57.519Z');
